<template>
    <section class="main-content">
        <loader :is-visible="isLoading"></loader>

        <div class="container-fluid p-0" v-if="IsShow">
            <div class="form-minheight">

                <div class="row mt-2 align-items-stretch">

                    <!-- LEFT SIDE -->
                    <div class="col-lg-6 leftsidediv" style="height: 100%; overflow-y: auto;">
                        <div class="col-md-12 p-0">
                            <div class="theme-primary partition">
                                <span class="p-name text-white">Links</span>
                            </div>
                        </div>

                        <div class="border p-2">

                            <div v-for="(module, index) in rightUrlList" :key="module.moduleMasterId"
                                class="w-100 clscontextmenu">
                                <h6 :class="{ 'mt-4': index > 0 }">{{ module.moduleName }}</h6>

                                <div class="links-box mainlist">
                            <div v-for="item in module.urlList" :key="item.privilegeId" class="button" :title="$t(item.displayName)">
                                <draggable :list="[item]" :group="{ name: 'urls', pull: true, put: false }" :sort="false" @change="onLeftListChange(item,module)" :move="onDragMove">
                                    <a class="box text-dark" >
                                        <em class="fa fa-ellipsis-v"></em>
                                        <em class="fa fa-ellipsis-v"></em>
                                        {{ $t(item.displayName) }}
                                    </a>
                                </draggable>
                            </div>


                                </div>

                            </div>
                        </div>
                    </div>

                    <!-- RIGHT SIDE -->
                    <div class="col-lg-6 rightsidediv">
                        <div class="accordion custom-accr" v-for="(module, index) in leftUrlList"
                            :key="module.moduleMasterId" :id="'accordionExample' + index">
                            <div class="card">

                                <!-- HEADER -->
                                <div class="card-header" :id="'heading' + index">
                                    <a data-toggle="collapse" :class="index !== 0 ? 'collapsed' : ''"
                                        :data-target="'#collapse' + index"
                                        :aria-expanded="index === 0 ? 'true' : 'false'"
                                        :aria-controls="'collapse' + index">
                                        <em class="fa fa-angle-down rotate-icon"></em>
                                        {{ module.moduleName }}
                                    </a>

                                    <span class="p-actions float-right" style="top:-1px;">
                                        <a href="javascript:;" class="addbutton p-action-btn text-white d-block"
                                            @click="addRow(module)">
                                            <em class="fa fa-plus"></em><br>
                                            {{ $t('AddNewRow') }}
                                        </a>
                                    </span>
                                </div>

                                <!-- COLLAPSE BODY -->
                                <div :id="'collapse' + index" class="collapse moduleList value_invitems_dynamic"
                                    :class="{ show: index === 0 }" :aria-labelledby="'heading' + index"
                                    :data-parent="'#accordionExample' + index">
                                    <div class="card-body p-0">
                                        <div class="p-2">

                                            <h6>{{ $t('LinkHeading') }}</h6>

                                            <!-- HEADERS -->
                                            <div class="appointment divHeader mb-3">
                                                <div class="form-group" v-for="n in 5" :key="n">
                                                    <input v-model="module.headers[n - 1]" class="form-control"
                                                        :placeholder="$t('LinksName')" />
                                                </div>
                                            </div>

                                            <h6>{{ $t('DragText') }}</h6>

                                            <!-- DRAGGABLE ROWS -->
                                            <div class="cm_topbot_padd w-100">
                                                
                                                    <div v-for="(row, rowIndex) in getRows(module)" :key="rowIndex"
                                                        class="page-menu">
                                                        <div v-for="(item, colIndex) in row" :key="colIndex"
                                                            class="draggablelist menu-box"
                                                            :id="module.moduleMasterId + '_urlId_' + item.displayOrder">
                                                            <draggable :list="[item]" :group="{ name: 'urls', pull: true, put: true }" :sort="false" 
                @change="(evt) => onItemAddedInSlot(evt, module, item.displayOrder)">
                                                                <a class="aFiltera leftaFiltera">
                                                                    <span>{{ $t(item.displayName) }}</span>
                                                                    <i v-if="item.displayName" class="fa fa-times aRemove" @click="removeItemm(module, item.displayOrder)"></i>
                                                                </a>
                                                            </draggable>
                                                        </div>
                                                        <!-- Delete Row Button -->
                                                        <div class="menu-box">
                                                            <a href="javascript:;" class="delRow bg-danger"
                                                                :class="{ disabled: rowIndex === 0 }"
                                                                @click="rowIndex !== 0 && deleteRow(module, rowIndex)">
                                                                <i class="fa fa-trash text-white"></i>
                                                            </a>
                                                        </div>
                                                    </div>
                                               
                                            </div>

                                        </div>
                                    </div>
                                </div>

                            </div>
                        </div>

                        <!-- SAVE BUTTONS -->
                        <div class="col-12">
                            <div class="row flex-row-reverse mt-2">
                                <div class="col-lg-6 text-right p-0">
                                    <a :title="$t('Save')" name="btnSave" href="javascript:;"
                                        class="btn btn-success mr-2" @click="saveContextMenu">
                                        <em class="fa fa-save pr-2"></em>{{ $t('Save') }}
                                    </a>
                                    <a :title="$t('Cancel')" class="btn btn-danger"  @click="cancelContextMenu">
                                        <em class="fa fa-close pr-2"></em>{{ $t('Cancel') }}
                                    </a>
                                </div>
                            </div>
                        </div>

                    </div>

                </div>


            </div>
        </div>
    </section>
</template>
<script>
import DataService from "../../services/DataService";
import draggable from 'vuedraggable';

export default {
    components: { draggable },
    data() {
        return {
            isLoading: false,
            IsShow:false,
            UserTypeId: 0,
            leftUrlList: [],
            rightUrlList: [],
            headerList: [],
        };
    },

    created() {
        this.setUserType();
        this.getContextMenuData();
    },

    methods: {
        setUserType() {
            const type = this.GetUserInfo?.UserType;
            this.UserTypeId = type === "CA" ? 1 : type === "PM" ? 2 : type === "CL" ? 4 : 3;
        },

        async getContextMenuData() {
            this.isLoading = true;
            const res = await DataService.GetContextMenuData(`Id=${this.UserTypeId}`);

            if (res.data) {
                this.rightUrlList = res.data.rightUrlList || [];
                const headerList = res.data.leftUrlHeaderList || [];
                const leftList = res.data.leftUrlList || [];

                this.leftUrlList = leftList.map(m => {
                    const headerData = headerList.find(h => h.moduleMasterId == m.moduleMasterId);
                    return {
                        moduleMasterId: m.moduleMasterId,
                        moduleName: m.moduleName,
                        headers: headerData
                            ? [
                                headerData.header1 || "",
                                headerData.header2 || "",
                                headerData.header3 || "",
                                headerData.header4 || "",
                                headerData.header5 || ""
                            ]
                            : ["", "", "", "", ""],
                        selectedUrls: (m.urlList || []).map((u, i) => ({
                            privilegeId: u.privilegeId,
                            displayName: u.displayName,
                            displayOrder: u.displayOrder || i + 1
                        }))
                    };
                });
                this.IsShow=true;
            } else {
                this.leftUrlList = [];
                this.rightUrlList = [];
            }
            this.isLoading = false;
        },

        addItemToRight(module, item) {
            // Check if any rows exist
            const hasRows = this.leftUrlList.some(m => 
                m.selectedUrls.length > 0 && 
                m.selectedUrls.some(x => x.privilegeId || x.displayName)
            );
            
            if (!hasRows) {                
                this.ShowAlert("TPlease add a row first before adding items", "warning", true, "Alert");
                return;
            }
            
            // Check if item already exists in this module's selectedUrls
            if (module.selectedUrls.some(x => x.privilegeId === item.privilegeId)) {                
                this.ShowAlert("This item already exists in the right side", "warning", true, "Alert");
                return;
            }
            
            // Find first empty slot
            const emptySlot = module.selectedUrls.find(x => !x.displayName);
            if (emptySlot) {
                emptySlot.privilegeId = item.privilegeId;
                emptySlot.displayName = item.displayName;
                
                // Remove from left side
                const leftModule = this.rightUrlList.find(m => m.moduleMasterId === module.moduleMasterId);
                if (leftModule) {
                    const leftIndex = leftModule.urlList.findIndex(x => x.privilegeId === item.privilegeId);
                    if (leftIndex > -1) {
                        leftModule.urlList.splice(leftIndex, 1);
                    }
                }
            }
        },

        removeItemm(module, order) {
            const item = module.selectedUrls.find(x => x.displayOrder === order);
            if (item) {
                // Get the item details before clearing
                const privilegeId = item.privilegeId;
                const displayName = item.displayName;
                
                item.displayName = "";
                item.privilegeId = 0;
                
                // Add back to left side
                if (privilegeId && displayName) {
                    const leftModule = this.rightUrlList.find(m => m.moduleMasterId === module.moduleMasterId);
                    if (leftModule) {
                        leftModule.urlList.push({
                            privilegeId: privilegeId,
                            displayName: displayName
                        });
                    }
                }
            }
        },

        deleteRow(module, rowIndex) {
            if (rowIndex === 0) return;
            let start = rowIndex * 5 + 1;
            let end = start + 4;
            module.selectedUrls = module.selectedUrls.filter(x => x.displayOrder < start || x.displayOrder > end);
            module.selectedUrls.forEach((item, index) => { item.displayOrder = index + 1; });
        },

        validateAllRowsFilled(module) {
            let total = module.selectedUrls.length;
            if (total === 0) return true;
            for (let i = 0; i < total; i += 5) {
                let row = module.selectedUrls.slice(i, i + 5);
                if (row.some(x => !x.displayName)) return false;
            }
            return true;
        },

        addRow(module) {
            if (!this.validateAllRowsFilled(module)) {                
                this.ShowAlert("Please fill all items in previous rows", "failure", true, "Alert");
                
                return;
            }
            if (module.selectedUrls.length >= 25) {                
                this.ShowAlert("Maximum 25 allowed", "failure", true, "Alert");
                return;
            }
            let startOrder = module.selectedUrls.length + 1;
            for (let i = 0; i < 5; i++) {
                module.selectedUrls.push({ privilegeId: 0, displayName: "", displayOrder: startOrder + i });
            }
        },

        getRows(module) {
            let rows = [];
            let total = module.selectedUrls.length;
            for (let i = 0; i < total; i += 5) {
                rows.push(module.selectedUrls.slice(i, i + 5));
            }
            // Don't show blank row if no rows exist - user must add row first
            return rows;
        },
        async saveContextMenu() {
            //debugger
            this.isLoading = true;

            let selectedUrl = [];
            let selectedHeaderUrl = [];
            let hasData = true;
            let hasHeaderData = true;
            let txtEmpty = true;

            // -----------------------------
            // 1. Validate all rows filled
            // -----------------------------
            this.leftUrlList.forEach(module => {
                if (!this.validateAllRowsFilled(module)) {
                    hasData = false;
                }
            });

            // -----------------------------
            // 2. Validate headers
            // -----------------------------
            this.leftUrlList.forEach(module => {
                const headers = module.headers.map(h => h.trim());

                // Check if all headers are filled
                if (headers.some(h => !h)) {
                    txtEmpty = false;
                }

                // Check for duplicates
                const sortedHeaders = [...headers].sort();
                const duplicates = sortedHeaders.filter((v, i, arr) => v && v === arr[i + 1]);
                if (duplicates.length > 0) {
                    hasHeaderData = false;
                }

                selectedHeaderUrl.push({
                    ModuleMasterId: module.moduleMasterId,
                    Header1: headers[0] || "",
                    Header2: headers[1] || "",
                    Header3: headers[2] || "",
                    Header4: headers[3] || "",
                    Header5: headers[4] || ""
                });
            });

            // -----------------------------
            // 3. Prepare selectedUrl data
            // -----------------------------
            this.leftUrlList.forEach(module => {
                module.selectedUrls.forEach(item => {
                    if (item.privilegeId && item.displayName) {
                        selectedUrl.push({
                            ModuleMasterId: module.moduleMasterId,
                            PrivilegeId: item.privilegeId,
                            DisplayOrder: item.displayOrder
                        });
                    }
                });
            });

            // -----------------------------
            // 4. Validation before save
            // -----------------------------
            if (!hasData) {
                this.isLoading = false;
                this.ShowAlert("Please fill all row items", "failure", true, "Alert");
                return;
            }

            if (!hasHeaderData) {
                this.isLoading = false;
                this.ShowAlert("Duplicate headers are not allowed", "failure", true, "Alert");
                return;
            }

            if (!txtEmpty) {
                this.isLoading = false;
                this.ShowAlert("Please fill all header names", "failure", true, "Alert");
                return;
            }

            if (selectedUrl.length === 0 || selectedHeaderUrl.length === 0) {
                this.isLoading = false;
                this.ShowAlert("Please add items before saving", "failure", true, "Alert");
                return;
            }

            // -----------------------------
            // 5. Save via API
            // -----------------------------    
            try {
                var Obj = {
                    modelData: selectedUrl,
                    modelHeader: selectedHeaderUrl,
                    userTypeId: this.UserTypeId
                };
                var JsonObj = JSON.stringify(Obj);
                const response = await DataService.SaveManageContextMenu(JsonObj);                
                this.isLoading = false;
                if (response.data.result.DATA[0].VALUE === 'Success') {
                    this.ShowAlert(this.$t('DataSavedContextMenu'), "success", true, "Alert");
                    this.$router.push({ name: 'ContextMenu'});
                } else {
                    this.ShowAlert(this.$t('ErrorWhileSavingData'), "failure", true, "Alert");
                }
            } catch (error) {
                this.isLoading = false;
                this.ShowAlert(this.$t('ErrorWhileSavingData'), "failure", true, "Alert");
            }
        },
        cloneItem(original) {
            return {
                privilegeId: original.privilegeId,
                displayName: original.displayName,
                displayOrder: 0
            };
        },

        onDragMove() {
            // Check if any rows exist (not just blank rows)
            const hasRealRows = this.leftUrlList.some(m => m.selectedUrls.length >= 5);
            
            if (!hasRealRows) {                
                this.ShowAlert("Please Add a new row first before dragging items", "failure", true, "Alert");
                return false;
            }
            return true;
        },

        onItemAddedInSlot(evt, module, displayOrder) {
            if (evt.added) {
                const newItem = evt.added.element;
                
                // Find the target slot in selectedUrls
                const targetSlot = module.selectedUrls.find(x => x.displayOrder === displayOrder);
                
                if (targetSlot) {
                    // Check if item already exists in another slot
                    const existingSlot = module.selectedUrls.find(x => 
                        x.privilegeId === newItem.privilegeId && 
                        x.displayName === newItem.displayName &&
                        x.displayOrder !== displayOrder
                    );
                    
                    if (existingSlot) {
                        // Remove the item from the slot (show empty)
                        targetSlot.privilegeId = 0;
                        targetSlot.displayName = "";                        
                        this.ShowAlert("This item already exists in the right side", "warning", true, "Alert");
                        return;
                    }
                    
                    // Fill the specific slot
                    targetSlot.privilegeId = newItem.privilegeId;
                    targetSlot.displayName = newItem.displayName;
                    
                    // Remove from left side
                    const leftModule = this.rightUrlList.find(m => m.moduleMasterId === module.moduleMasterId);
                    if (leftModule) {
                        const leftIndex = leftModule.urlList.findIndex(x => x.privilegeId === newItem.privilegeId);
                        if (leftIndex > -1) {
                            leftModule.urlList.splice(leftIndex, 1);
                        }
                    }
                }
            }
        },
        onLeftListChange(module) {
            // Re-index display order for left side if needed
            module.urlList.forEach((el, index) => {
                if (el.displayOrder !== index + 1) {
                    el.displayOrder = index + 1;
                }
            });
        },
        updateDisplayOrder(module) {
            module.selectedUrls.forEach((item, index) => {
                item.displayOrder = index + 1;
            });
        },
        cancelContextMenu(){
            this.$router.push({ name: 'ContextMenu'});
        }




    }
};
</script>

<style>
.delRow.disabled {
    opacity: 0.4;
    pointer-events: none;
    cursor: not-allowed;
}

</style>